Hi guys,

As I expleined in this issue #396, it happens when Filter contains one FilterRules.

It fails with this configuration:
```
{
   "QueueConfigurations":[
      {
         "Id":"S3EventsSQSNotification",
         "QueueArn":"arn:aws:sqs:us-east-1:queue:devInventoryLoaderEvents",
         "Events":[
            "s3:ObjectCreated:*"
         ],
         "Filter":{
            "Key":{
               "FilterRules":[
                  {
                     "Name":"prefix",
                     "Value":"workspace"
                  }
             ]
            }
         }
      }
   ]
}
```
It works with this one:

```
{
   "QueueConfigurations":[
      {
         "Id":"S3EventsSQSNotification",
         "QueueArn":"arn:aws:sqs:us-east-1:queue:devInventoryLoaderEvents",
         "Events":[
            "s3:ObjectCreated:*"
         ],
         "Filter":{
            "Key":{
               "FilterRules":[
                  {
                     "Name":"prefix",
                     "Value":"workspace"
                  }, {
                    "Name":"prefix",
                    "Value":"workspace"
                 }
             ]
            }
         }
      }
   ]
}

```

